    60→            = PooledDictionary<NamedTypeSymbol, NamedTypeSymbol>.CreatePool(Symbols.SymbolEqualityComparer.IgnoringNullable);
    61→
    62→        internal static PooledDictionary<NamedTypeSymbol, NamedTypeSymbol> GetInstance()
    63→        {
    64→            var instance = s_poolInstance.Allocate();
    65→            Debug.Assert(instance.Count == 0);
    66→            return instance;
    67→        }
    68→    }
    69→
    70→    // Method type inference can fail, but we still might have some best guesses. 
